var fs = require("fs");

// Create a readable stream from source file
var readable = fs.createReadStream("input.txt", { highWaterMark: 4096 });

// Create a writable stream to destination file
var writable = fs.createWriteStream("output.txt");

// Pipe handles backpressure automatically
readable.pipe(writable);

// Listen for completion
writable.on("finish", function() {
  console.log("File copied successfully");
});

readable.on("error", function(err) {
  console.error("Read error:", err.message);
});

writable.on("error", function(err) {
  console.error("Write error:", err.message);
});

var Transform = require("stream").Transform;

function UpperCaseTransform() {
  Transform.call(this, { encoding: "utf8" });
}

UpperCaseTransform.prototype = Object.create(Transform.prototype);

UpperCaseTransform.prototype._transform = function(chunk, encoding, callback) {
  try {
    var upper = chunk.toString().toUpperCase();
    this.push(upper);
    callback();
  } catch (err) {
    callback(err);
  }
};

var upper = new UpperCaseTransform();
process.stdin.pipe(upper).pipe(process.stdout);

// Usage: echo "hello world" | node upper.js
// Output: HELLO WORLD

var fs = require("fs");

var readable = fs.createReadStream("large-file.txt");
var writable = fs.createWriteStream("output.txt");

function writeData() {
  var chunk;
  while (null !== (chunk = readable.read())) {
    var canContinue = writable.write(chunk);
    if (!canContinue) {
      console.log("Backpressure: pausing read");
      readable.pause();
      writable.once("drain", function() {
        console.log("Buffer drained: resuming read");
        writeData();
      });
      return;
    }
  }
}

readable.on("readable", writeData);

writable.on("finish", function() {
  console.log("Write complete");
});

var http = require("http");

http.get("http://example.com/large-file", function(response) {
  var chunks = [];
  var totalSize = 0;

  response.on("data", function(chunk) {
    chunks.push(chunk);
    totalSize += chunk.length;
    console.log("Received chunk:", chunk.length, "bytes");
  });

  response.on("end", function() {
    var buffer = Buffer.concat(chunks);
    console.log("Total received:", totalSize, "bytes");
    console.log("Complete body:", buffer.toString());
  });

  response.on("error", function(err) {
    console.error("Stream error:", err.message);
  });

  // Pause if we need to slow down consumption
  response.pause();
  setTimeout(function() { response.resume(); }, 1000);
}).on("error", function(err) {
  console.error("Request error:", err.message);
});

var fs = require("fs");
var zlib = require("zlib");
var pipeline = require("stream").pipeline;

// Read a file, compress it, and write to new file
var source = fs.createReadStream("input.txt");
var gzip = zlib.createGzip();
var destination = fs.createWriteStream("input.txt.gz");

pipeline(source, gzip, destination, function(err) {
  if (err) {
    console.error("Pipeline failed:", err.message);
    return;
  }
  console.log("File compressed successfully");
});

// pipeline() destroys all streams on error automatically
// Unlike pipe(), errors propagate to the callback
// All streams are properly cleaned up even on failure
